module.render:

    const color = args.color || 'var(--accent-color)';
    const titleStr = sections[0] ? sections[0].trim() : '';
    const contentStr = sections[1] ? sections[1].trim() : '';
    return `\n\n<div class="mdp-mod-infobox" style="border-left-color: ${color};"><div class="infobox-header" style="color: ${color};">

${titleStr}

</div><div class="infobox-body">

${contentStr}

</div></div>\n\n`;
